【图1·代码填空题】根据图1，补全下列 C51 程序（12 MHz，delay_ms 已实现），使 P0.0 所接 LED 每秒闪烁一次：

#include <______>
sbit LED = ______;

void main(void) {
    while(______) {
        LED = ______;
        delay_ms(500);
        LED = ______;
        delay_ms(500);
    }
}

answer:
（1）#include <reg51.h>
sbit LED = P0^0;
void delay_ms(unsigned int ms);
（2）void main(void) {
    while (1) {
        LED = 1; delay_ms(250);
        LED = 0; delay_ms(250);
    }
}

（1）unsigned char code seg[]={0x3F,0x06,0x5B,0x4F,0x66,0x6D,0x7D,0x07,0x7F,0x6F};
unsigned char buf[6]={0,1,2,3,4,5};
（2）void scan_display(void){
  unsigned char i;
  for(i=0;i<6;i++){
    P0=seg[buf[i]]; P2=~(1<<i);
    P1_0=1; P1_0=0; delay_ms(2);
  }
}

