【图3·代码填空题】补全矩阵键盘扫描与双位显示（行 P1.0~P1.3 输出，列 P1.4~P1.7 输入，P2.x=1 选中该位）：

for (row = ______; row < 4; row++) {
    P1 = (~(______ << row)) & ______ | 0xF0;
    if ((P1 & ______) != 0xF0) return row * 4 + col_index;
}
P0 = seg[tens];  P2 = ______;   /* 选十位 */
P0 = seg[ones];  P2 = ______;   /* 选个位 */

answer:
（1）unsigned char key_scan(void){
  unsigned char row,col;
  for(row=0;row<4;row++){
    P1=(~(0x01<<row))&0x0F|0xF0;
    if((P1&0xF0)!=0xF0) return row*4+col_index;
  } return 0xFF;
}
（2）while(1){
  k=key_scan();
  if(k!=0xFF){ delay_ms(10); if(key_scan()==k){ tens=k/10; ones=k%10; }}
  scan_2digit(tens,ones); /* P2=0x01 选十位，P2=0x02 选个位 */
}

