【图4·代码填空题】补全交通灯控制（高电平点亮，P0.0~P0.2 东西，P0.3~P0.5 南北）：

sbit EW_R = ______;
sbit EW_G = ______;
sbit NS_R = ______;

P0 = ______;              /* 先全灭 */
EW_G = 1; NS_R = 1;       /* 东西绿、南北红 → P0=______ */

P0 = 0x00;
EW_R = 1; NS_G = 1;       /* 南北绿、东西红 → P0=______ */

answer:
（1）typedef enum{EW_G,EW_Y,ALL_R,NS_G,NS_Y} STATE;
void light_state(STATE s){
  switch(s){
    case EW_G: P0=0x0C; break;
    case EW_Y: P0=0x0A; break;
    case ALL_R: P0=0x09; break;
    case NS_G: P0=0x21; break;
    case NS_Y: P0=0x11; break;
  }
}
（2）while(1){ light_state(st); delay_ms(30000/3000/2000); st=(st+1)%5; }

