【图1·代码填空题·变式】用位操作控制 P0.0 上的 LED（不定义 sbit）：

#include <______>

void main(void) {
    while(______) {
        P0 = P0 ______ 0x01;    /* 点亮 */
        delay_ms(100);
        P0 = P0 ______ 0xFE;    /* 熄灭 */
        delay_ms(______) ;       /* 灭 900 ms */
    }
}

answer:
（1）void delay_1ms(void){ unsigned char i; for(i=0;i<250;i++); }
（2）void main(void){
  unsigned int i;
  while(1){
    P0|=0x01; for(i=0;i<100;i++) delay_1ms();
    P0&=0xFE; for(i=0;i<900;i++) delay_1ms();
  }
}

