【图3·代码填空题·变式】0~99 计数显示（P2.x=1 选中，边沿检测）：

unsigned char cnt = ______, pk = 0xFF, k;

k = key_scan();
if (k == ______ && pk == 0xFF) {
    cnt = (cnt + ______) % 100;
    pk = k;
}
if (k == ______) pk = 0xFF;

scan_2digit(cnt/______, cnt%10);

answer:
（1）void scan_2digit(uchar t,uchar o){
  P0=seg[t]; P2=0x01;
  P0=seg[o]; P2=0x02;
}
（2）while(1){
  k=key_scan();
  if(k==1&&pk==0xFF){ cnt=(cnt+1)%100; pk=k; }
  if(k==0xFF) pk=0xFF;
  scan_2digit(cnt/10,cnt%10);
}

